const accounts = [
  { handle: 'nateherk', platform: 'youtube' },
  { handle: 'oalanicolas', platform: 'youtube' },
  { handle: 'jovensdenegocios', platform: 'youtube' },
  { handle: 'horadenegocios', platform: 'youtube' },
  { handle: 'Academia.Lendaria', platform: 'youtube' },
  { handle: 'Chase-H-AI', platform: 'youtube' },
  { handle: 'danmartell', platform: 'youtube' },
  { handle: 'BenAI92', platform: 'youtube' },
  { handle: 'Itssssss_Jack', platform: 'youtube' }
];
return accounts.map(a => ({ json: a }));

const results = [];

for (const item of $input.all()) {
  const response = item.json;
  let handle = 'unknown';
  try { handle = $('All YT Accounts').item.json.handle; } catch(e) {}

  for (const video of (response.items || [])) {
    const stats = video.statistics || {};
    const snippet = video.snippet || {};
    const title = (snippet.title || '').trim();
    if (!title) continue;

    const likes = parseInt(stats.likeCount || 0);
    const comments = parseInt(stats.commentCount || 0);
    const views = parseInt(stats.viewCount || 1);

    // Engagement score: (likes + comments*10) / views — ratio of active interaction to reach
    const engagementScore = parseFloat(((likes + comments * 10) / Math.max(views, 1) * 100).toFixed(6));

    results.push({
      json: {
        video_id: String(video.id),
        video_url: 'https://www.youtube.com/watch?v=' + video.id,
        source_account: handle,
        title: title,
        description_as_script: (snippet.description || '').substring(0, 2000),
        likes: likes,
        comments: comments,
        views: views,
        engagement_score: engagementScore,
        published_at: snippet.publishedAt || null
      }
    });
  }
}

// Sort by engagement score, return top 3
results.sort((a, b) => b.json.engagement_score - a.json.engagement_score);
return results.slice(0, 3);

