const claudeResponse = $input.first().json;
const videoData = $('Score & Filter Videos').item.json;

let analysis = {};
try {
  const text = claudeResponse.content && claudeResponse.content[0] && claudeResponse.content[0].text
    ? claudeResponse.content[0].text.trim()
    : '{}';
  const cleaned = text.replace(/^```json?\n?|```$/gm, '').trim();
  analysis = JSON.parse(cleaned);
} catch(e) {
  analysis = {
    hook_text: videoData.title ? videoData.title.substring(0, 120) : '',
    content_topic: 'unknown',
    is_timeless: false,
    tech_stack: [],
    narrative_structure: { hook: '', main_content: '', conclusion: '' },
    why_it_worked: 'Analysis failed: ' + e.message,
    reel_adaptation: '',
    youtube_channel_fit: '',
    relevance_score: 0
  };
}

return [{ json: { ...videoData, ...analysis } }];
